import Cluster from "@/components/primitives/Cluster";
import Container from "@/components/primitives/Container";
import Link from "@/components/primitives/Link";
import Stack from "@/components/primitives/Stack";
import { hero } from "@/content/landing/hero";

const HERO_STYLES = `
.landing-hero {
  padding-top: var(--s-9);
  padding-bottom: var(--s-7);
}
@media (max-width: 640px) {
  .landing-hero {
    padding-top: var(--s-7);
    padding-bottom: var(--s-6);
  }
}
`;

export default function Hero() {
  return (
    <Container as="section" size="base" className="landing-hero">
      <style>{HERO_STYLES}</style>
      <Stack gap={5}>
        <h1 className="t-headline">{hero.name}</h1>
        <p className="t-mono-body">{hero.tagline}</p>
        <p className="t-prose">{hero.description}</p>
        <Cluster gap={3}>
          <Link
            href={hero.primaryCta.href}
            variant="underline"
            style={{
              color: "var(--accent)",
              textDecorationColor: "var(--accent)",
            }}
          >
            {hero.primaryCta.label}
          </Link>
          <Link href={hero.secondaryCta.href} variant="subtle">
            {hero.secondaryCta.label}
          </Link>
        </Cluster>
      </Stack>
    </Container>
  );
}

// Sentences below are sourced from src/content/about/biography.ts.
// biography.ts contains 8 sentences across 4 paragraphs; the four most
// informative are kept here. Dropped:
//   - P1-S1 ("Michael Quintin works on systems that help operators think
//     clearly...") — already paraphrased in the hero description.
//   - P2-S2 ("It exists because the standard tools for strategy work...") —
//     long motivation aside; covered by P2-S1 stating Hivemind's nature.
//   - P2-S3 ("Hivemind makes the work durable.") — too thin in isolation.
//   - P4-S1 ("Theseus is the smallest of the three projects and the most
//     personal.") — subjective framing without payload; its sole role here
//     was naming the antecedent of P4-S2's pronoun "It", so the fourth
//     entry below substitutes "Theseus" for "It".
export const bio = {
  heading: "Briefly",
  body: [
    "His current projects share a single throughline: the production of structure where the dominant institutions produce noise.",
    "Hivemind is a strategic analytical software company.",
    "Purposeless Efficiency, the first volume of a five-book series, is the corresponding written argument: that efficiency severed from purpose has become the dominant production logic of the late industrial era, and that this severance has consequences that any honest political economy must now treat as central.",
    "Theseus is a knowledge system for monitoring ideological contradiction — a slow, structured collaborator for the operator-philosopher who wants to know, at any given moment, where their stated commitments contradict themselves.",
  ],
};

import identity from "@/content/about/identity";

export const hero = {
  name: identity.name,
  tagline: "researcher and builder of strategic-analytical software",
  description:
    "I work on systems that help operators think clearly in a world optimized against clear thinking. My projects share a single throughline: the production of structure where dominant institutions produce noise. Hivemind, Purposeless Efficiency, and Theseus are the current expressions of that work.",
  primaryCta: { label: "Ask my LLM about my work", href: "/chat" },
  secondaryCta: { label: "Read my projects", href: "/projects" },
};

